import{_ as e,o as t,c as s,j as r,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"地狱火霰弹枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/地狱火霰弹枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/地狱火霰弹枪.md"}'),_={name:"4.资源分区/7.物品与装备/2.武器/远程武器/2.C级/地狱火霰弹枪.md"};function d(l,a,b,i,p,c){return t(),s("div",null,[...a[0]||(a[0]=[r("h1",{id:"地狱火霰弹枪",tabindex:"-1"},[n("地狱火霰弹枪 "),r("a",{class:"header-anchor",href:"#地狱火霰弹枪","aria-label":'Permalink to "地狱火霰弹枪"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调017")])])],-1),o('<h1 id="地狱火霰弹枪-1" tabindex="-1">地狱火霰弹枪 <a class="header-anchor" href="#地狱火霰弹枪-1" aria-label="Permalink to &quot;地狱火霰弹枪&quot;">​</a></h1><p>地狱火霰弹枪<br> “听上去英国佬很有把握。英雄永远是英雄，加布里尔。雕像上的那个英雄可不是我”<br> 这个后来被称为死神的人，本名加布里尔莱耶斯。他出生于洛杉矶。智械危机开始前，他成为了美国军队的高级军官，是一名久经沙场、受人敬佩的老兵。因技战术精湛后加入了实验性小队守望先锋，并被给予了这把地狱火霰弹枪。在随后升职？黑色守望队长期间，手下遗传学家莫伊拉对其进行了改造，使他获得了某些超乎常理的能力（无论是地狱火霰弹枪还是布里尔莱耶斯本人）。<br> 本质：科技本质<br> 价格：C+1000<br> 制造商：守望先锋<br> 类型：霰弹枪<br> 体积：4<br> 武器伤害：12L<br> 弹药类型：无限<br> 装弹量：4 发（不可拆卸管状弹仓）<br> 操作原理：泵动式<br> 基础射程：40米</p><p>特性：<br> -地狱火霰弹枪的弹道扩散很大，因此，其有效射程要比一般的枪械近得多，在超出基础射程后，在远距离上将几乎不产生任何伤害。不过，因其较大的扩散范围，换来的是对极近距离内单位的伤害，当对距离你不超过15米的目标射击时，地狱火霰弹枪武器伤害提高3L，同时获得破甲5和威猛3。</p><p>特殊的是，在购买本武器后，你会获得无数把完全一致的地狱火霰弹枪，但这些地狱火霰弹枪都视为处于一个特殊的储物空间中，只有你可以从中取出和使用，该武器若交由他人使用，会立刻消失。但是同时生效枪械的只能有一把，取出和存入是一个迅捷动作（存取两把或者一把武器动作相同），重新取出的地狱火霰弹枪总视为满备弹状态。<br> 需要注意的时：<br> -及时备战专长或类似能力，可以降低地狱火霰弹枪取出和存入的动作需求；<br> 人物可以进行连续射击，这视为进行了一次【短点射】。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',6)])])}const f=e(_,[["render",d]]);export{m as __pageData,f as default};
